1788→                        "operation = %s", srcFolderId, messages.size(), destFolderId, operation.name());
1789→
1790→                MessageStore messageStore = messageStoreManager.getMessageStore(account);
1791→
1792→                List<Long> messageIds = new ArrayList<>();
1793→                Map<Long, String> messageIdToUidMapping = new HashMap<>();
1794→                for (LocalMessage message : messages) {
1795→                    long messageId = message.getDatabaseId();
1796→                    messageIds.add(messageId);
1797→                    messageIdToUidMapping.put(messageId, message.getUid());
1798→                }
1799→
1800→                Map<Long, Long> resultIdMapping;
1801→                if (operation == MoveOrCopyFlavor.COPY) {
1802→                    resultIdMapping = messageStore.copyMessages(messageIds, destFolderId);
1803→
1804→                    if (unreadCountAffected) {
1805→                        // If this copy operation changes the unread count in the destination
